// C3: Physical sensing components
instance InputCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor input current I_M, publishing via MQTT"
    DTDFVocab:producedData InputCurrentDataTransmitted
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder providing angular position of the motor shaft"
    DTDFVocab:producedData MotorAngleDataTransmitted
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox encoder providing angular position after the cycloidal gearbox"
    DTDFVocab:producedData GearboxAngleDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance InputCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom InputCurrentSensor
]

instance MotorAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

