]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Live motor shaft angle trace from the motor encoder"
    DTDFVocab:fromData MotorAngleDataTransmitted
    DTDFVocab:inputTo MQTTBroker, SimulinkFrictionEngine
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Live gearbox output angle trace from the gearbox encoder"
    DTDFVocab:fromData GearboxAngleDataTransmitted
    DTDFVocab:inputTo MQTTBroker, SimulinkFrictionEngine
]

